// CUDA kernel definition

template <typename T, int BLOCKDIM, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_func(T seed, T* g_data, size_t total_size) {
	const unsigned int blockSize = BLOCKDIM;
#ifdef BLOCK_STRIDED
	const int stride = blockSize;
	const int idx = blockIdx.x * blockSize * ELEMENTS_PER_THREAD + threadIdx.x;
#else
	const int grid_size = blockSize * gridDim.x;
	const int stride = grid_size;
	const int idx = blockIdx.x * blockDim.x + threadIdx.x;
#endif
	const int big_stride = gridDim.x * blockSize * ELEMENTS_PER_THREAD;

	if (idx >= total_size) return;

	T tmps[ELEMENTS_PER_THREAD];
	for(int k=0; k<FUSION_DEGREE; k++){	
		#pragma unroll
		for(int j=0; j<ELEMENTS_PER_THREAD; j++){
			size_t pos = idx + j*stride + k*big_stride;
			if(pos < total_size)
				tmps[j] = g_data[pos];
			else
				tmps[j] = (T)0;

			for(int i=0; i<COMPUTE_ITERATIONS; i++){
				tmps[j] = tmps[j]*tmps[j]+seed;
			}
		}

		T sum = (T)0;
		#pragma unroll
		for(int j=0; j+1<ELEMENTS_PER_THREAD; j+=2)
			sum += tmps[j]*tmps[j+1];

		if( is_equal<T>(sum, (T)-1) ) 
			g_data[idx+k*big_stride] = sum;
	}
}

