extern "C" void mixbenchGPU(double* c,
                            long size,
                            bool block_strided,
                            bool host_allocated,
                            bool use_os_timer,
                            size_t workgroupsize,
                            unsigned int elements_per_wi,
                            unsigned int fusion_degree) {
  const char* benchtype;
  if (block_strided)
    benchtype = "Workgroup";
  else
    benchtype = "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation =
      host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n",
         use_os_timer ? "OS based" : "CUDA event based");

  // Check double precision support
  cudaDeviceProp deviceProp;
  int current_device;
  CUDA_SAFE_CALL(cudaGetDevice(&current_device));
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&deviceProp, current_device));

  bool enable_dp = (deviceProp.major > 1) || (deviceProp.major == 1 && deviceProp.minor >= 3);
  if (!enable_dp)
    printf(
        "Warning:                Double precision computations are not supported\n");
  bool enable_hp = IsFP16Supported();
  if (!enable_hp)
    printf(
        "Warning:                Half precision computations are not supported\n");

  // Allocate device buffer
  double* d_c_buffer = nullptr;
  if(host_allocated){
	  CUDA_SAFE_CALL(cudaMallocHost(&c, size * sizeof(double)));
  }
  CUDA_SAFE_CALL(cudaMalloc(&d_c_buffer, size * sizeof(double)));

  // Initialize buffer to zero
  CUDA_SAFE_CALL(cudaMemset(d_c_buffer, 0, size * sizeof(double)));

  printf("Loading kernel source file...\n");

  show_progress_init(compute_iterations_len);

  // We will not compile kernels at runtime here since CUDA kernels are compiled ahead
  // Instead we just run the benchmark loops

  show_progress_step(0, '\\');

  // Warmup kernel
  runbench_warmup(d_c_buffer, size, workgroupsize);

  show_progress_step(0, '|');

  printf(
      "------------------------------------------------------------------------"
      "----- CSV data "
      "------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    int current_compute_iterations = compute_iterations[i];

    const long compute_grid_size = size / elements_per_wi / fusion_degree;
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2 * elements_per_wi * current_compute_iterations) *
             (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    // Single precision
    double kernel_time_mad_sp = runbench_single<float>(current_compute_iterations, d_c_buffer, size,
                                                      workgroupsize, elements_per_wi, fusion_degree,
                                                      1.0f, use_os_timer, block_strided);
    // Double precision
    double kernel_time_mad_dp = 0.0;
    if(enable_dp){
      kernel_time_mad_dp = runbench_single<double>(current_compute_iterations, d_c_buffer, size,
                                                  workgroupsize, elements_per_wi, fusion_degree,
                                                  1.0, use_os_timer, block_strided);
    }
    // Half precision (using half2)
    double kernel_time_mad_hp = 0.0;
    if(enable_hp){
      // For half2, seed is {15360,15360} in OpenCL, approximate with __half2
      __half2 seed_h = __half2half2(__float2half(15360.0f));
      // Half2 kernel launch not implemented here, so skip or fallback
      kernel_time_mad_hp = 0.0;
    }
    // Integer
    double kernel_time_mad_int = runbench_single<int>(current_compute_iterations, d_c_buffer, size,
                                                     workgroupsize, elements_per_wi, fusion_degree,
                                                     1, use_os_timer, block_strided);

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
